    await post({ ...VALID_BODY, en: 200, boy: 260, pileStili: 'Düz Pile', pileOrani: 2.5, kanat: 'Çift Kanat' });

    const draftBody = JSON.parse(bodies[0]) as {
      draft_order: { line_items: { properties: { name: string; value: string }[] }[] };
