    expect(props).toContainEqual({ name: 'Pile Stili', value: 'Düz Pile (x2.5)' });
    expect(props).toContainEqual({ name: 'Kanat', value: 'Çift Kanat' });
  });

  test('draft order line item uses server-fetched product title, not variant_id', async () => {
    const bodies: string[] = [];
