   560→  <script>
   561→    (function() {
   562→      // ─── Logger ─────────────────────────────────────────────────────────────
   563→      function log(event, data) {
   564→        if (data !== undefined) {
   565→          console.log('[PerdeTasarla] ' + event, data);
   566→        } else {
   567→          console.log('[PerdeTasarla] ' + event);
   568→        }
   569→      }
   570→
   571→      var MIN_EN  = 50;
   572→      var confEl  = document.getElementById('curtain-configurator');
   573→      var MAX_BOY = parseInt(confEl.dataset.maxBoy, 10) || 300;
   574→      window.perdeConfig = window.perdeConfig || {};
   575→
   576→      var BASE_PRICE = parseFloat(confEl.dataset.basePrice) || 0;
   577→      var VARIANT_ID = parseInt(confEl.dataset.variantId, 10);
   578→      var API_URL    = confEl.dataset.apiUrl || '';
   579→
   580→      log('init', {
   581→        basePrice:  BASE_PRICE,
   582→        variantId:  VARIANT_ID,
   583→        maxBoy:     MAX_BOY,
   584→        apiUrl:     API_URL ? 'configured' : 'MISSING',
   585→        apiUrlHost: API_URL ? API_URL.replace(/^https?:\/\//, '').split('/')[0] : null
   586→      });
   587→
   588→      /* ---------- Step 1 ---------- */
   589→      var enInput      = document.getElementById('perde-en');
   590→      var boyInput     = document.getElementById('perde-boy');
   591→      var enError      = document.getElementById('perde-en-error');
   592→      var boyError     = document.getElementById('perde-boy-error');
   593→      var step1Btn     = document.getElementById('perde-step1-btn');
   594→      var step1El      = document.getElementById('perde-step-1');
   595→      var summary1     = document.getElementById('perde-summary-1');
   596→      var summary1Text = document.getElementById('perde-summary-1-text');
   597→      var step2El      = document.getElementById('perde-step-2');
   598→
   599→      function validateEn() {
   600→        var v = parseInt(enInput.value, 10);
   601→        var ok = !isNaN(v) && v >= MIN_EN;
   602→        enInput.classList.toggle('is-invalid', !ok && enInput.value !== '');
   603→        enError.classList.toggle('is-visible', !ok && enInput.value !== '');
   604→        if (!ok && enInput.value !== '') log('validate:en:fail', { value: enInput.value, min: MIN_EN });
   605→        return ok;
   606→      }
   607→
   608→      function validateBoy() {
   609→        var v = parseInt(boyInput.value, 10);
   610→        var ok = !isNaN(v) && v >= 1 && v <= MAX_BOY;
   611→        boyInput.classList.toggle('is-invalid', !ok && boyInput.value !== '');
   612→        boyError.classList.toggle('is-visible', !ok && boyInput.value !== '');
   613→        if (!ok && boyInput.value !== '') log('validate:boy:fail', { value: boyInput.value, max: MAX_BOY });
   614→        return ok;
   615→      }
   616→
   617→      function updateStep1Btn() {
   618→        step1Btn.disabled = !(validateEn() && validateBoy());
   619→      }
   620→
   621→      enInput.addEventListener('input', updateStep1Btn);
   622→      boyInput.addEventListener('input', updateStep1Btn);
   623→
   624→      step1Btn.addEventListener('click', function() {
   625→        if (step1Btn.disabled) return;
   626→        window.perdeConfig.en  = parseInt(enInput.value, 10);
   627→        window.perdeConfig.boy = parseInt(boyInput.value, 10);
   628→        log('step1:complete', { en: window.perdeConfig.en, boy: window.perdeConfig.boy });
   629→        step1El.classList.remove('is-active');
   630→        summary1Text.textContent = window.perdeConfig.en + ' x ' + window.perdeConfig.boy + ' cm';
   631→        summary1.classList.add('is-visible');
   632→        step2El.classList.add('is-active');
   633→      });
   634→
   635→      /* ---------- Step 2 ---------- */
   636→      var step2Btn     = document.getElementById('perde-step2-btn');
   637→      var summary2     = document.getElementById('perde-summary-2');
   638→      var summary2Text = document.getElementById('perde-summary-2-text');
   639→      var pileCards    = document.querySelectorAll('.perde-conf__pile-card');
   640→      var step3El      = document.getElementById('perde-step-3');
   641→      var summary3     = document.getElementById('perde-summary-3');
   642→
   643→      pileCards.forEach(function(card) {
   644→        card.addEventListener('click', function() {
   645→          pileCards.forEach(function(c) {
   646→            c.classList.remove('is-selected');
   647→            c.setAttribute('aria-pressed', 'false');
   648→          });
   649→          card.classList.add('is-selected');
   650→          card.setAttribute('aria-pressed', 'true');
   651→          window.perdeConfig.pile_stili = card.dataset.pile;
   652→          window.perdeConfig.pile_orani = parseFloat(card.dataset.ratio);
   653→          step2Btn.disabled = false;
   654→          log('step2:select', { pile: card.dataset.pile, ratio: card.dataset.ratio });
   655→        });
   656→        card.addEventListener('keydown', function(e) {
   657→          if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); card.click(); }
   658→        });
   659→      });
   660→
   661→      step2Btn.addEventListener('click', function() {
   662→        if (step2Btn.disabled) return;
   663→        log('step2:complete', { pile: window.perdeConfig.pile_stili, ratio: window.perdeConfig.pile_orani });
   664→        step2El.classList.remove('is-active');
   665→        summary2Text.textContent = window.perdeConfig.pile_stili;
   666→        summary2.classList.add('is-visible');
   667→        step3El.classList.add('is-active');
   668→      });
   669→
   670→      /* ---------- Step 3 ---------- */
   671→      var step3Btn     = document.getElementById('perde-step3-btn');
   672→      var summary3Text = document.getElementById('perde-summary-3-text');
   673→      var kanatOptions = document.querySelectorAll('.perde-conf__kanat-option');
   674→
   675→      kanatOptions.forEach(function(opt) {
   676→        opt.addEventListener('click', function() {
   677→          kanatOptions.forEach(function(o) {
   678→            o.classList.remove('is-selected');
   679→            o.setAttribute('aria-pressed', 'false');
   680→          });
   681→          opt.classList.add('is-selected');
   682→          opt.setAttribute('aria-pressed', 'true');
   683→          window.perdeConfig.kanat       = opt.dataset.kanat;
   684→          window.perdeConfig.kanat_count = parseInt(opt.dataset.count, 10);
   685→          step3Btn.disabled = false;
   686→          log('step3:select', { kanat: opt.dataset.kanat, count: opt.dataset.count });
   687→        });
   688→        opt.addEventListener('keydown', function(e) {
   689→          if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); opt.click(); }
   690→        });
   691→      });
   692→
   693→      step3Btn.addEventListener('click', function() {
   694→        if (step3Btn.disabled) return;
   695→        log('step3:complete', { kanat: window.perdeConfig.kanat, count: window.perdeConfig.kanat_count });
   696→        step3El.classList.remove('is-active');
   697→        summary3Text.textContent = window.perdeConfig.kanat;
   698→        summary3.classList.add('is-visible');
   699→        showStep4();
   700→      });
   701→
   702→      /* ---------- Step 4 ---------- */
   703→      var step4El         = document.getElementById('perde-step-4');
   704→      var priceDisplay    = document.getElementById('perde-price-display');
   705→      var reviewEn        = document.getElementById('perde-review-en');
   706→      var reviewBoy       = document.getElementById('perde-review-boy');
   707→      var reviewPile      = document.getElementById('perde-review-pile');
   708→      var reviewKanat     = document.getElementById('perde-review-kanat');
   709→      var disclaimerCheck = document.getElementById('perde-disclaimer-check');
   710→      var cartError       = document.getElementById('perde-cart-error');
   711→      var addToCartBtn    = document.getElementById('perde-add-to-cart-btn');
   712→
   713→      function formatTL(amount) {
   714→        return amount.toLocaleString('tr-TR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + ' TL';
   715→      }
   716→
   717→      function calcPrice() {
   718→        var en    = window.perdeConfig.en || 0;
   719→        var ratio = window.perdeConfig.pile_orani || 1;
   720→        var count = window.perdeConfig.kanat_count || 1;
   721→        var price = (en / 100) * ratio * count * BASE_PRICE;
   722→        log('price:formula', {
   723→          formula: '(' + en + '/100) × ' + ratio + ' × ' + count + ' × ' + BASE_PRICE,
   724→          result: price,
   725→          resultFormatted: formatTL(price)
   726→        });
   727→        return price;
   728→      }
   729→
   730→      function showStep4() {
   731→        var price = calcPrice();
   732→        reviewEn.textContent     = (window.perdeConfig.en || '—') + ' cm';
   733→        reviewBoy.textContent    = (window.perdeConfig.boy || '—') + ' cm';
   734→        reviewPile.textContent   = window.perdeConfig.pile_stili || '—';
   735→        reviewKanat.textContent  = window.perdeConfig.kanat || '—';
   736→        priceDisplay.textContent = formatTL(price);
   737→        step4El.classList.add('is-active');
   738→        log('step4:show', {
   739→          config: {
   740→            en: window.perdeConfig.en, boy: window.perdeConfig.boy,
   741→            pile: window.perdeConfig.pile_stili, ratio: window.perdeConfig.pile_orani,
   742→            kanat: window.perdeConfig.kanat, count: window.perdeConfig.kanat_count
   743→          },
   744→          price: formatTL(price)
   745→        });
   746→      }
   747→
   748→      disclaimerCheck.addEventListener('change', function() {
   749→        addToCartBtn.disabled = !disclaimerCheck.checked;
   750→        log('disclaimer:' + (disclaimerCheck.checked ? 'accepted' : 'unaccepted'));
   751→      });
   752→
   753→      // Clear any stale draft order URL when configurator loads
   754→      try { sessionStorage.removeItem('perdeCheckoutUrl'); } catch(e) {}
   755→
   756→      addToCartBtn.addEventListener('click', function() {
   757→        if (addToCartBtn.disabled) return;
   758→        if (!API_URL) {
   759→          cartError.textContent = 'Sipariş API adresi yapılandırılmamış. Lütfen yöneticiyle iletişime geçin.';
   760→          cartError.classList.add('is-visible');
   761→          log('error:no-api-url');
   762→          return;
   763→        }
   764→
   765→        addToCartBtn.disabled = true;
   766→        addToCartBtn.textContent = 'Hazırlanıyor…';
   767→        cartError.classList.remove('is-visible');
   768→        cartError.textContent = '';
   769→
   770→        var cfg = window.perdeConfig;
   771→        var calculatedPrice = calcPrice();
   772→        var calculatedCents = Math.round(calculatedPrice * 100);
   773→
   774→        var draftPayload = {
   775→          variantId:  VARIANT_ID,
   776→          en:         cfg.en,
   777→          boy:        cfg.boy,
   778→          pileStili:  cfg.pile_stili,
   779→          pileOrani:  cfg.pile_orani,
   780→          kanat:      cfg.kanat,
   781→          kanatCount: cfg.kanat_count
   782→        };
   783→        log('cart:draft-order:request', draftPayload);
   784→
   785→        // Step 1: create draft order to get a checkout URL with the correct calculated price
   786→        fetch(API_URL + '/api/checkout/draft-order', {
   787→          method: 'POST',
   788→          headers: { 'Content-Type': 'application/json' },
   789→          body: JSON.stringify(draftPayload)
   790→        })
   791→        .then(function(res) {
   792→          return res.json().then(function(data) {
   793→            if (!res.ok) throw new Error(data.message || 'Sipariş oluşturulamadı.');
   794→            return data;
   795→          });
   796→        })
   797→        .then(function(data) {
   798→          if (!data.checkoutUrl) throw new Error('Ödeme sayfası alınamadı.');
   799→          log('cart:draft-order:response', { checkoutUrl: data.checkoutUrl.substring(0, 60) + '…' });
   800→          // Store the draft order checkout URL — the checkout interception listener will use it
   801→          try { sessionStorage.setItem('perdeCheckoutUrl', data.checkoutUrl); } catch(e) {}
   802→
   803→          var cartItemsEl   = document.querySelector('cart-items-component[data-section-id]');
   804→          var cartSectionId = cartItemsEl ? cartItemsEl.dataset.sectionId : '';
   805→
   806→          var cartPayload = {
   807→            id:       VARIANT_ID,
   808→            quantity: 1,
   809→            sections: cartSectionId,
   810→            properties: {
   811→              'En':                cfg.en + ' cm',
   812→              'Boy':               cfg.boy + ' cm',
   813→              'Pile Stili':        cfg.pile_stili + ' (x' + cfg.pile_orani + ')',
   814→              'Kanat':             cfg.kanat,
   815→              'Hesaplanan Fiyat':  formatTL(calculatedPrice),
   816→              '_hesaplanan_cents': calculatedCents
   817→            }
   818→          };
   819→          log('cart:add:request', { variantId: cartPayload.id, properties: cartPayload.properties });
   820→
   821→          // Step 2: add to cart so the item appears in the cart drawer
   822→          return fetch('/cart/add.js', {
   823→            method: 'POST',
   824→            headers: { 'Content-Type': 'application/json' },
   825→            body: JSON.stringify(cartPayload)
   826→          });
   827→        })
   828→        .then(function(res) {
   829→          return res.json().then(function(data) {
   830→            if (!res.ok) throw new Error(data.description || 'Sepete eklenemedi.');
   831→            return data;
   832→          });
   833→        })
   834→        .then(function(cartData) {
   835→          var sectionsData = cartData.sections || {};
   836→          log('cart:add:response', { itemCount: cartData.item_count, sectionsRendered: Object.keys(sectionsData).length });
   837→          addToCartBtn.textContent = 'Sepete Eklendi ✓';
   838→          log('cart:add:complete', { price: formatTL(calculatedPrice) });
   839→
   840→          var evt = new CustomEvent('cart:update', { bubbles: true, detail: { data: { sections: sectionsData } } });
   841→          document.dispatchEvent(evt);
   842→
   843→          var cartDrawer = document.querySelector('cart-drawer-component');
   844→          if (cartDrawer) {
   845→            cartDrawer.open();
   846→            log('cart:drawer:opened');
   847→          } else {
   848→            log('cart:drawer:not-found');
   849→          }
   850→        })
   851→        .catch(function(err) {
   852→          log('cart:error', { message: err.message });
   853→          cartError.textContent = err.message || 'Hata oluştu. Lütfen tekrar deneyin.';
   854→          cartError.classList.add('is-visible');
   855→          addToCartBtn.disabled = false;
   856→          addToCartBtn.textContent = 'Sepete Ekle';
   857→        });
   858→      });
   859→
   860→      // Intercept checkout button clicks and redirect to the draft order URL (correct price)
   861→      document.addEventListener('click', function(e) {
   862→        var checkoutUrl;
   863→        try { checkoutUrl = sessionStorage.getItem('perdeCheckoutUrl'); } catch(e2) {}
   864→        if (!checkoutUrl) return;
   865→
   866→        var target = e.target.closest('a[href*="/checkout"], button[name="checkout"], [data-checkout-btn]');
   867→        if (target) {
   868→          e.preventDefault();
   869→          e.stopImmediatePropagation();
   870→          log('checkout:intercepted', { url: checkoutUrl.substring(0, 60) + '…' });
   871→          try { sessionStorage.removeItem('perdeCheckoutUrl'); } catch(e2) {}
   872→          window.location.href = checkoutUrl;
   873→        }
   874→      }, true);
   875→
   876→    })();
   877→
   878→    // Move configurator into the product details column, below the description
   879→    document.addEventListener('DOMContentLoaded', function() {
   880→      var conf = document.getElementById('curtain-configurator');
   881→      var target = document.querySelector('.product-details .group-block-content');
   882→      if (conf && target) {
   883→        conf.classList.remove('page-width');
   884→        target.appendChild(conf);
   885→      }
   886→
   887→      // Resolve measurement section anchor dynamically
   888→      var measureLink = document.getElementById('perde-measure-link');
   889→      if (measureLink) {
   890→        var measureSection = document.querySelector('[id*="measurement_videos_pdp"]');
   891→        if (measureSection) {
   892→          measureLink.href = '#' + measureSection.id;
   893→        }
   894→      }
   895→    });
   896→  </script>
   897→{% endif %}
   898→
   899→{% schema %}
   900→{
   901→  "name": "Perde Tasarla",
   902→  "tag": "section",
   903→  "settings": [
   904→    {
   905→      "type": "text",
   906→      "id": "draft_order_api_url",
   907→      "label": "Draft Order API URL",
   908→      "info": "PMS sunucu adresi. Örn: https://pms.inanctekstil.store"
   909→    }
   910→  ]
   911→}
   912→{% endschema %}
