{% if product.tags contains 'perde-tasarla' %}
  {% assign max_boy = product.metafields.custom.max_boy_cm | default: 300 %}

  <style>
    variant-picker,
    .buy-buttons-block,
    sticky-add-to-cart {
      display: none !important;
    }

    .perde-conf {
      font-family: var(--font-body--family, 'Inter', sans-serif);
      color: #333333;
      max-width: 560px;
      margin: 32px 0;
    }

    /* ---- Active step card ---- */
    .perde-conf__step {
      border: 1px solid #E5E5E5;
      border-radius: 8px;
      padding: 24px;
      background: #FFFFFF;
      display: none;
    }

    .perde-conf__step.is-active {
      display: block;
    }

    .perde-conf__step-title {
      font-family: var(--font-primary--family, 'Playfair Display', serif);
      font-size: 1.1rem;
      font-weight: 700;
      color: #1B2A4A;
      margin: 0 0 20px 0;
    }

    /* ---- Collapsed summary rows ---- */
    .perde-conf__summary {
      display: none;
      border: 1px solid #E5E5E5;
      border-radius: 8px;
      padding: 14px 20px;
      background: #F8F8F8;
      font-size: 0.9rem;
      color: #333333;
      margin-bottom: 12px;
    }

    .perde-conf__summary.is-visible {
      display: flex;
      align-items: center;
      justify-content: space-between;
    }

    .perde-conf__summary-label {
      font-weight: 600;
      color: #1B2A4A;
      margin-right: 8px;
    }

    /* ---- Step 1: measure hint link ---- */
    .perde-conf__measure-hint {
      font-size: 0.82rem;
      color: #888;
      margin: -8px 0 20px 0;
    }

    .perde-conf__measure-link {
      color: #1B2A4A;
      text-decoration: underline;
      text-underline-offset: 2px;
    }

    .perde-conf__measure-link:hover {
      opacity: 0.75;
    }

    /* ---- Step 1: measurement inputs ---- */
    .perde-conf__diagram {
      display: flex;
      justify-content: center;
      margin-bottom: 24px;
    }

    .perde-conf__fields {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 16px;
      margin-bottom: 20px;
    }

    .perde-conf__field label {
      display: block;
      font-size: 0.85rem;
      font-weight: 600;
      color: #1B2A4A;
      margin-bottom: 6px;
    }

    .perde-conf__field input {
      width: 100%;
      padding: 10px 12px;
      border: 1px solid #E5E5E5;
      border-radius: 6px;
      font-size: 1rem;
      color: #333333;
      box-sizing: border-box;
      outline: none;
      transition: border-color 0.15s;
    }

    .perde-conf__field input:focus {
      border-color: #1B2A4A;
    }

    .perde-conf__field input.is-invalid {
      border-color: #c0392b;
    }

    .perde-conf__error {
      display: none;
      font-size: 0.78rem;
      color: #c0392b;
      margin-top: 4px;
    }

    .perde-conf__error.is-visible {
      display: block;
    }

    /* ---- Step 2: pile card picker ---- */
    .perde-conf__pile-cards {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 12px;
      margin-bottom: 20px;
    }

    .perde-conf__pile-card {
      border: 2px solid #E5E5E5;
      border-radius: 8px;
      padding: 0;
      cursor: pointer;
      transition: border-color 0.15s, box-shadow 0.15s;
      background: #F8F8F8;
      text-align: center;
      overflow: hidden;
    }

    .perde-conf__pile-card:hover {
      border-color: #1B2A4A;
    }

    .perde-conf__pile-card.is-selected {
      border-color: #1B2A4A;
      box-shadow: 0 0 0 2px #1B2A4A22;
    }

    .perde-conf__pile-card__img {
      width: 100%;
      aspect-ratio: 1;
      background: #ffffff;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 0.7rem;
      color: #999;
      position: relative;
    }

    .perde-conf__pile-card__img svg {
      opacity: 0.4;
    }

    .perde-conf__pile-card__label {
      padding: 10px 6px;
      font-size: 0.82rem;
      font-weight: 600;
      color: #1B2A4A;
      line-height: 1.3;
    }

    .perde-conf__pile-card__ratio {
      font-size: 0.72rem;
      color: #888;
      font-weight: 400;
    }

    /* ---- Step 3: kanat options ---- */
    .perde-conf__kanat-options {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 12px;
      margin-bottom: 20px;
    }

    .perde-conf__kanat-option {
      border: 2px solid #E5E5E5;
      border-radius: 8px;
      padding: 16px 12px;
      cursor: pointer;
      transition: border-color 0.15s, box-shadow 0.15s;
      background: #F8F8F8;
      text-align: center;
    }

    .perde-conf__kanat-option:hover {
      border-color: #1B2A4A;
    }

    .perde-conf__kanat-option.is-selected {
      border-color: #1B2A4A;
      box-shadow: 0 0 0 2px #1B2A4A22;
    }

    .perde-conf__kanat-option__img {
      display: flex;
      justify-content: center;
      margin-bottom: 10px;
    }

    .perde-conf__kanat-option__label {
      font-size: 0.9rem;
      font-weight: 600;
      color: #1B2A4A;
      margin-bottom: 4px;
    }

    .perde-conf__kanat-option__desc {
      font-size: 0.78rem;
      color: #666;
      line-height: 1.4;
    }

    /* ---- Shared button ---- */
    .perde-conf__btn {
      width: 100%;
      padding: 14px;
      background: #1B2A4A;
      color: #FFFFFF;
      border: none;
      border-radius: 6px;
      font-size: 1rem;
      font-weight: 600;
      cursor: pointer;
      transition: opacity 0.15s;
    }

    .perde-conf__btn:disabled {
      opacity: 0.4;
      cursor: not-allowed;
    }

    /* ---- Step 4: config summary table ---- */
    .perde-conf__review-table {
      border: 1px solid #E5E5E5;
      border-radius: 8px;
      overflow: hidden;
      margin-bottom: 20px;
    }

    .perde-conf__review-row {
      display: flex;
      justify-content: space-between;
      padding: 10px 16px;
      font-size: 0.9rem;
      color: #333;
      border-bottom: 1px solid #E5E5E5;
    }

    .perde-conf__review-row:last-child {
      border-bottom: none;
    }

    .perde-conf__review-row-label {
      font-weight: 600;
      color: #1B2A4A;
    }

    /* ---- Price block ---- */
    .perde-conf__price-block {
      background: #F8F8F8;
      border: 1px solid #E5E5E5;
      border-radius: 8px;
      padding: 16px 20px;
      margin-bottom: 20px;
      text-align: center;
    }

    .perde-conf__price-label {
      font-size: 0.78rem;
      color: #888;
      text-transform: uppercase;
      letter-spacing: 0.05em;
      margin-bottom: 6px;
    }

    .perde-conf__price-value {
      font-size: 1.6rem;
      font-weight: 700;
      color: #1B2A4A;
      font-family: var(--font-primary--family, 'Playfair Display', serif);
      margin-bottom: 4px;
    }

    .perde-conf__price-note {
      font-size: 0.75rem;
      color: #888;
    }

    /* ---- Disclaimer checkbox ---- */
    .perde-conf__disclaimer {
      display: flex;
      gap: 10px;
      align-items: flex-start;
      padding: 14px 16px;
      background: #FFFBF0;
      border: 1px solid #EDD98A;
      border-radius: 8px;
      margin-bottom: 16px;
      font-size: 0.85rem;
      color: #555;
      cursor: pointer;
      line-height: 1.5;
    }

    .perde-conf__disclaimer input[type="checkbox"] {
      flex-shrink: 0;
      width: 18px;
      height: 18px;
      margin-top: 2px;
      accent-color: #1B2A4A;
      cursor: pointer;
    }

    /* ---- Cart error ---- */
    .perde-conf__cart-error {
      display: none;
      color: #c0392b;
      font-size: 0.85rem;
      padding: 10px 14px;
      background: #FDF0EF;
      border: 1px solid #F5C6C3;
      border-radius: 6px;
      margin-bottom: 12px;
    }

    .perde-conf__cart-error.is-visible {
      display: block;
    }
  </style>

  <div id="curtain-configurator" class="curtain-configurator page-width"
    data-max-boy="{{ max_boy }}"
    data-base-price="{{ product.selected_or_first_available_variant.price | divided_by: 100.0 }}"
    data-variant-id="{{ product.selected_or_first_available_variant.id }}"
    data-api-url="{{ section.settings.draft_order_api_url | escape }}">
    <div class="perde-conf">

      <!-- Collapsed summary: Step 1 -->
      <div id="perde-summary-1" class="perde-conf__summary">
        <span><span class="perde-conf__summary-label">Ölçü:</span><span id="perde-summary-1-text"></span></span>
      </div>

      <!-- Step 1: Ölçü Seçimi -->
      <div id="perde-step-1" class="perde-conf__step is-active">
        <p class="perde-conf__step-title">1. Ölçü Seçimi</p>

        <div class="perde-conf__diagram">
          <svg width="160" height="140" viewBox="0 0 160 140" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
            <rect x="30" y="10" width="100" height="110" fill="#F8F8F8" stroke="#1B2A4A" stroke-width="2"/>
            <line x1="50" y1="10" x2="50" y2="120" stroke="#E5E5E5" stroke-width="1" stroke-dasharray="4 3"/>
            <line x1="70" y1="10" x2="70" y2="120" stroke="#E5E5E5" stroke-width="1" stroke-dasharray="4 3"/>
            <line x1="90" y1="10" x2="90" y2="120" stroke="#E5E5E5" stroke-width="1" stroke-dasharray="4 3"/>
            <line x1="110" y1="10" x2="110" y2="120" stroke="#E5E5E5" stroke-width="1" stroke-dasharray="4 3"/>
            <line x1="30" y1="132" x2="130" y2="132" stroke="#1B2A4A" stroke-width="1.5"/>
            <polygon points="30,128 30,136 22,132" fill="#1B2A4A"/>
            <polygon points="130,128 130,136 138,132" fill="#1B2A4A"/>
            <text x="80" y="128" text-anchor="middle" font-size="11" fill="#1B2A4A" font-weight="600">EN</text>
            <line x1="144" y1="10" x2="144" y2="120" stroke="#1B2A4A" stroke-width="1.5"/>
            <polygon points="140,10 148,10 144,2" fill="#1B2A4A"/>
            <polygon points="140,120 148,120 144,128" fill="#1B2A4A"/>
            <text x="144" y="70" text-anchor="middle" font-size="11" fill="#1B2A4A" font-weight="600" transform="rotate(90,144,70)">BOY</text>
          </svg>
        </div>

        <div class="perde-conf__fields">
          <div class="perde-conf__field">
            <label for="perde-en">En (cm)</label>
            <input type="number" id="perde-en" min="50" placeholder="örn. 200">
            <span class="perde-conf__error" id="perde-en-error">En en az 50 cm olmalıdır</span>
          </div>
          <div class="perde-conf__field">
            <label for="perde-boy">Boy (cm)</label>
            <input type="number" id="perde-boy" min="1" max="{{ max_boy }}" placeholder="örn. 250">
            <span class="perde-conf__error" id="perde-boy-error">Boy en fazla {{ max_boy }} cm olabilir</span>
          </div>
        </div>

        <p class="perde-conf__measure-hint">
          Ölçü almayı bilmiyor musunuz?
          <a id="perde-measure-link" href="#" class="perde-conf__measure-link">Perde Ölçüsü Nasıl Alınır? →</a>
        </p>

        <button class="perde-conf__btn" id="perde-step1-btn" disabled>Devam Et</button>
      </div>

      <!-- Collapsed summary: Step 2 -->
      <div id="perde-summary-2" class="perde-conf__summary">
        <span><span class="perde-conf__summary-label">Pile:</span><span id="perde-summary-2-text"></span></span>
      </div>

      <!-- Step 2: Pile Stili -->
      <div id="perde-step-2" class="perde-conf__step">
        <p class="perde-conf__step-title">2. Pile Stili</p>

        <div class="perde-conf__pile-cards">
          <!-- Düz Dikiş -->
          <div class="perde-conf__pile-card" data-pile="Düz Dikiş" data-ratio="2.0" role="button" tabindex="0" aria-pressed="false">
            <div class="perde-conf__pile-card__img">
              <svg width="60" height="60" viewBox="0 0 60 60" fill="none">
                <rect x="5" y="5" width="50" height="50" fill="#D5D5D5" rx="2"/>
                <line x1="5" y1="15" x2="55" y2="15" stroke="#bbb" stroke-width="1"/>
                <line x1="5" y1="25" x2="55" y2="25" stroke="#bbb" stroke-width="1"/>
                <line x1="5" y1="35" x2="55" y2="35" stroke="#bbb" stroke-width="1"/>
                <line x1="5" y1="45" x2="55" y2="45" stroke="#bbb" stroke-width="1"/>
              </svg>
            </div>
            <div class="perde-conf__pile-card__label">
              Düz Dikiş<br>
              <span class="perde-conf__pile-card__ratio">x2.0</span>
            </div>
          </div>
          <!-- Kanun Pile -->
          <div class="perde-conf__pile-card" data-pile="Kanun Pile" data-ratio="2.5" role="button" tabindex="0" aria-pressed="false">
            <div class="perde-conf__pile-card__img">
              <svg width="60" height="60" viewBox="0 0 60 60" fill="none">
                <rect x="5" y="5" width="50" height="50" fill="#D5D5D5" rx="2"/>
                <path d="M10 55 Q15 30 20 55 Q25 30 30 55 Q35 30 40 55 Q45 30 50 55" stroke="#aaa" stroke-width="1.5" fill="none"/>
              </svg>
            </div>
            <div class="perde-conf__pile-card__label">
              Kanun Pile<br>
              <span class="perde-conf__pile-card__ratio">x2.5</span>
            </div>
          </div>
          <!-- Boru Pile -->
          <div class="perde-conf__pile-card" data-pile="Boru Pile" data-ratio="3.0" role="button" tabindex="0" aria-pressed="false">
            <div class="perde-conf__pile-card__img">
              <svg width="60" height="60" viewBox="0 0 60 60" fill="none">
                <rect x="5" y="5" width="50" height="50" fill="#D5D5D5" rx="2"/>
                <line x1="15" y1="5" x2="15" y2="55" stroke="#aaa" stroke-width="2"/>
                <line x1="25" y1="5" x2="25" y2="55" stroke="#aaa" stroke-width="2"/>
                <line x1="35" y1="5" x2="35" y2="55" stroke="#aaa" stroke-width="2"/>
                <line x1="45" y1="5" x2="45" y2="55" stroke="#aaa" stroke-width="2"/>
              </svg>
            </div>
            <div class="perde-conf__pile-card__label">
              Boru Pile<br>
              <span class="perde-conf__pile-card__ratio">x3.0</span>
            </div>
          </div>
        </div>

        <button class="perde-conf__btn" id="perde-step2-btn" disabled>Devam Et</button>
      </div>

      <!-- Collapsed summary: Step 3 -->
      <div id="perde-summary-3" class="perde-conf__summary">
        <span><span class="perde-conf__summary-label">Kanat:</span><span id="perde-summary-3-text"></span></span>
      </div>

      <!-- Step 3: Kanat Seçimi -->
      <div id="perde-step-3" class="perde-conf__step">
        <p class="perde-conf__step-title">3. Kanat Seçimi</p>

        <div class="perde-conf__kanat-options">
          <!-- Tek Kanat -->
          <div class="perde-conf__kanat-option" data-kanat="Tek Kanat" data-count="1" role="button" tabindex="0" aria-pressed="false">
            <div class="perde-conf__kanat-option__img">
              <svg width="64" height="72" viewBox="0 0 64 72" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                <rect x="16" y="4" width="32" height="60" fill="#E5E5E5" stroke="#1B2A4A" stroke-width="2"/>
                <line x1="22" y1="4" x2="22" y2="64" stroke="#C5C5C5" stroke-width="1" stroke-dasharray="3 3"/>
                <line x1="30" y1="4" x2="30" y2="64" stroke="#C5C5C5" stroke-width="1" stroke-dasharray="3 3"/>
                <line x1="38" y1="4" x2="38" y2="64" stroke="#C5C5C5" stroke-width="1" stroke-dasharray="3 3"/>
                <line x1="46" y1="4" x2="46" y2="64" stroke="#C5C5C5" stroke-width="1" stroke-dasharray="3 3"/>
                <line x1="16" y1="4" x2="48" y2="4" stroke="#1B2A4A" stroke-width="2.5"/>
              </svg>
            </div>
            <div class="perde-conf__kanat-option__label">Tek Kanat</div>
            <div class="perde-conf__kanat-option__desc">Tek parça perde, tek tarafa açılır.</div>
          </div>
          <!-- Çift Kanat -->
          <div class="perde-conf__kanat-option" data-kanat="Çift Kanat" data-count="2" role="button" tabindex="0" aria-pressed="false">
            <div class="perde-conf__kanat-option__img">
              <svg width="64" height="72" viewBox="0 0 64 72" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                <rect x="2" y="4" width="27" height="60" fill="#E5E5E5" stroke="#1B2A4A" stroke-width="2"/>
                <line x1="8"  y1="4" x2="8"  y2="64" stroke="#C5C5C5" stroke-width="1" stroke-dasharray="3 3"/>
                <line x1="15" y1="4" x2="15" y2="64" stroke="#C5C5C5" stroke-width="1" stroke-dasharray="3 3"/>
                <line x1="22" y1="4" x2="22" y2="64" stroke="#C5C5C5" stroke-width="1" stroke-dasharray="3 3"/>
                <rect x="35" y="4" width="27" height="60" fill="#E5E5E5" stroke="#1B2A4A" stroke-width="2"/>
                <line x1="41" y1="4" x2="41" y2="64" stroke="#C5C5C5" stroke-width="1" stroke-dasharray="3 3"/>
                <line x1="48" y1="4" x2="48" y2="64" stroke="#C5C5C5" stroke-width="1" stroke-dasharray="3 3"/>
                <line x1="55" y1="4" x2="55" y2="64" stroke="#C5C5C5" stroke-width="1" stroke-dasharray="3 3"/>
                <line x1="2"  y1="4" x2="62" y2="4" stroke="#1B2A4A" stroke-width="2.5"/>
              </svg>
            </div>
            <div class="perde-conf__kanat-option__label">Çift Kanat</div>
            <div class="perde-conf__kanat-option__desc">İki parça perde, ortadan her iki yana açılır.</div>
          </div>
        </div>

        <button class="perde-conf__btn" id="perde-step3-btn" disabled>Devam Et</button>
      </div>

      <!-- Step 4: Onay -->
      <div id="perde-step-4" class="perde-conf__step">
        <p class="perde-conf__step-title">4. Onay</p>

        <div class="perde-conf__review-table">
          <div class="perde-conf__review-row">
            <span class="perde-conf__review-row-label">En</span>
            <span id="perde-review-en">—</span>
          </div>
          <div class="perde-conf__review-row">
            <span class="perde-conf__review-row-label">Boy</span>
            <span id="perde-review-boy">—</span>
          </div>
          <div class="perde-conf__review-row">
            <span class="perde-conf__review-row-label">Pile Stili</span>
            <span id="perde-review-pile">—</span>
          </div>
          <div class="perde-conf__review-row">
            <span class="perde-conf__review-row-label">Kanat</span>
            <span id="perde-review-kanat">—</span>
          </div>
        </div>

        <div class="perde-conf__price-block">
          <div class="perde-conf__price-label">Tahmini Fiyat</div>
          <div class="perde-conf__price-value" id="perde-price-display">—</div>
          <div class="perde-conf__price-note">Sepette kesinleşir.</div>
        </div>

        <label class="perde-conf__disclaimer">
          <input type="checkbox" id="perde-disclaimer-check">
          <span>Bu perde özel olarak dikileceği için iade edilemez. Ölçülerimi kontrol ettiğimi onaylıyorum.</span>
        </label>

        <div class="perde-conf__cart-error" id="perde-cart-error"></div>

        <button class="perde-conf__btn" id="perde-add-to-cart-btn" disabled>Sepete Ekle</button>
      </div>

    </div>
  </div>

  <script>
    (function() {
      // ─── Logger ─────────────────────────────────────────────────────────────
      function log(event, data) {
        if (data !== undefined) {
          console.log('[PerdeTasarla] ' + event, data);
        } else {
          console.log('[PerdeTasarla] ' + event);
        }
      }

      var MIN_EN  = 50;
      var confEl  = document.getElementById('curtain-configurator');
      var MAX_BOY = parseInt(confEl.dataset.maxBoy, 10) || 300;
      window.perdeConfig = window.perdeConfig || {};

      var BASE_PRICE = parseFloat(confEl.dataset.basePrice) || 0;
      var VARIANT_ID = parseInt(confEl.dataset.variantId, 10);
      var API_URL    = confEl.dataset.apiUrl || '';

      log('init', {
        basePrice:  BASE_PRICE,
        variantId:  VARIANT_ID,
        maxBoy:     MAX_BOY,
        apiUrl:     API_URL ? 'configured' : 'MISSING',
        apiUrlHost: API_URL ? API_URL.replace(/^https?:\/\//, '').split('/')[0] : null
      });

      /* ---------- Step 1 ---------- */
      var enInput      = document.getElementById('perde-en');
      var boyInput     = document.getElementById('perde-boy');
      var enError      = document.getElementById('perde-en-error');
      var boyError     = document.getElementById('perde-boy-error');
      var step1Btn     = document.getElementById('perde-step1-btn');
      var step1El      = document.getElementById('perde-step-1');
      var summary1     = document.getElementById('perde-summary-1');
      var summary1Text = document.getElementById('perde-summary-1-text');
      var step2El      = document.getElementById('perde-step-2');

      function validateEn() {
        var v = parseInt(enInput.value, 10);
        var ok = !isNaN(v) && v >= MIN_EN;
        enInput.classList.toggle('is-invalid', !ok && enInput.value !== '');
        enError.classList.toggle('is-visible', !ok && enInput.value !== '');
        if (!ok && enInput.value !== '') log('validate:en:fail', { value: enInput.value, min: MIN_EN });
        return ok;
      }

      function validateBoy() {
        var v = parseInt(boyInput.value, 10);
        var ok = !isNaN(v) && v >= 1 && v <= MAX_BOY;
        boyInput.classList.toggle('is-invalid', !ok && boyInput.value !== '');
        boyError.classList.toggle('is-visible', !ok && boyInput.value !== '');
        if (!ok && boyInput.value !== '') log('validate:boy:fail', { value: boyInput.value, max: MAX_BOY });
        return ok;
      }

      function updateStep1Btn() {
        step1Btn.disabled = !(validateEn() && validateBoy());
      }

      enInput.addEventListener('input', updateStep1Btn);
      boyInput.addEventListener('input', updateStep1Btn);

      step1Btn.addEventListener('click', function() {
        if (step1Btn.disabled) return;
        window.perdeConfig.en  = parseInt(enInput.value, 10);
        window.perdeConfig.boy = parseInt(boyInput.value, 10);
        log('step1:complete', { en: window.perdeConfig.en, boy: window.perdeConfig.boy });
        step1El.classList.remove('is-active');
        summary1Text.textContent = window.perdeConfig.en + ' x ' + window.perdeConfig.boy + ' cm';
        summary1.classList.add('is-visible');
        step2El.classList.add('is-active');
      });

      /* ---------- Step 2 ---------- */
      var step2Btn     = document.getElementById('perde-step2-btn');
      var summary2     = document.getElementById('perde-summary-2');
      var summary2Text = document.getElementById('perde-summary-2-text');
      var pileCards    = document.querySelectorAll('.perde-conf__pile-card');
      var step3El      = document.getElementById('perde-step-3');
      var summary3     = document.getElementById('perde-summary-3');

      pileCards.forEach(function(card) {
        card.addEventListener('click', function() {
          pileCards.forEach(function(c) {
            c.classList.remove('is-selected');
            c.setAttribute('aria-pressed', 'false');
          });
          card.classList.add('is-selected');
          card.setAttribute('aria-pressed', 'true');
          window.perdeConfig.pile_stili = card.dataset.pile;
          window.perdeConfig.pile_orani = parseFloat(card.dataset.ratio);
          step2Btn.disabled = false;
          log('step2:select', { pile: card.dataset.pile, ratio: card.dataset.ratio });
        });
        card.addEventListener('keydown', function(e) {
          if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); card.click(); }
        });
      });

      step2Btn.addEventListener('click', function() {
        if (step2Btn.disabled) return;
        log('step2:complete', { pile: window.perdeConfig.pile_stili, ratio: window.perdeConfig.pile_orani });
        step2El.classList.remove('is-active');
        summary2Text.textContent = window.perdeConfig.pile_stili;
        summary2.classList.add('is-visible');
        step3El.classList.add('is-active');
      });

      /* ---------- Step 3 ---------- */
      var step3Btn     = document.getElementById('perde-step3-btn');
      var summary3Text = document.getElementById('perde-summary-3-text');
      var kanatOptions = document.querySelectorAll('.perde-conf__kanat-option');

      kanatOptions.forEach(function(opt) {
        opt.addEventListener('click', function() {
          kanatOptions.forEach(function(o) {
            o.classList.remove('is-selected');
            o.setAttribute('aria-pressed', 'false');
          });
          opt.classList.add('is-selected');
          opt.setAttribute('aria-pressed', 'true');
          window.perdeConfig.kanat       = opt.dataset.kanat;
          window.perdeConfig.kanat_count = parseInt(opt.dataset.count, 10);
          step3Btn.disabled = false;
          log('step3:select', { kanat: opt.dataset.kanat, count: opt.dataset.count });
        });
        opt.addEventListener('keydown', function(e) {
          if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); opt.click(); }
        });
      });

      step3Btn.addEventListener('click', function() {
        if (step3Btn.disabled) return;
        log('step3:complete', { kanat: window.perdeConfig.kanat, count: window.perdeConfig.kanat_count });
        step3El.classList.remove('is-active');
        summary3Text.textContent = window.perdeConfig.kanat;
        summary3.classList.add('is-visible');
        showStep4();
      });

      /* ---------- Step 4 ---------- */
      var step4El         = document.getElementById('perde-step-4');
      var priceDisplay    = document.getElementById('perde-price-display');
      var reviewEn        = document.getElementById('perde-review-en');
      var reviewBoy       = document.getElementById('perde-review-boy');
      var reviewPile      = document.getElementById('perde-review-pile');
      var reviewKanat     = document.getElementById('perde-review-kanat');
      var disclaimerCheck = document.getElementById('perde-disclaimer-check');
      var cartError       = document.getElementById('perde-cart-error');
      var addToCartBtn    = document.getElementById('perde-add-to-cart-btn');

      function formatTL(amount) {
        return amount.toLocaleString('tr-TR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + ' TL';
      }

      function calcPrice() {
        var en    = window.perdeConfig.en || 0;
        var ratio = window.perdeConfig.pile_orani || 1;
        var count = window.perdeConfig.kanat_count || 1;
        var price = (en / 100) * ratio * count * BASE_PRICE;
        log('price:formula', {
          formula: '(' + en + '/100) × ' + ratio + ' × ' + count + ' × ' + BASE_PRICE,
          result: price,
          resultFormatted: formatTL(price)
        });
        return price;
      }

      function showStep4() {
        var price = calcPrice();
        reviewEn.textContent     = (window.perdeConfig.en || '—') + ' cm';
        reviewBoy.textContent    = (window.perdeConfig.boy || '—') + ' cm';
        reviewPile.textContent   = window.perdeConfig.pile_stili || '—';
        reviewKanat.textContent  = window.perdeConfig.kanat || '—';
        priceDisplay.textContent = formatTL(price);
        step4El.classList.add('is-active');
        log('step4:show', {
          config: {
            en: window.perdeConfig.en, boy: window.perdeConfig.boy,
            pile: window.perdeConfig.pile_stili, ratio: window.perdeConfig.pile_orani,
            kanat: window.perdeConfig.kanat, count: window.perdeConfig.kanat_count
          },
          price: formatTL(price)
        });
      }

      disclaimerCheck.addEventListener('change', function() {
        addToCartBtn.disabled = !disclaimerCheck.checked;
        log('disclaimer:' + (disclaimerCheck.checked ? 'accepted' : 'unaccepted'));
      });

      // Clear any stale draft order URL when configurator loads
      try { sessionStorage.removeItem('perdeCheckoutUrl'); } catch(e) {}

      addToCartBtn.addEventListener('click', function() {
        if (addToCartBtn.disabled) return;
        if (!API_URL) {
          cartError.textContent = 'Sipariş API adresi yapılandırılmamış. Lütfen yöneticiyle iletişime geçin.';
          cartError.classList.add('is-visible');
          log('error:no-api-url');
          return;
        }

        addToCartBtn.disabled = true;
        addToCartBtn.textContent = 'Hazırlanıyor…';
        cartError.classList.remove('is-visible');
        cartError.textContent = '';

        var cfg = window.perdeConfig;
        var calculatedPrice = calcPrice();
        var calculatedCents = Math.round(calculatedPrice * 100);

        var draftPayload = {
          variantId:  VARIANT_ID,
          en:         cfg.en,
          boy:        cfg.boy,
          pileStili:  cfg.pile_stili,
          pileOrani:  cfg.pile_orani,
          kanat:      cfg.kanat,
          kanatCount: cfg.kanat_count
        };
        log('cart:draft-order:request', draftPayload);

        // Step 1: create draft order to get a checkout URL with the correct calculated price
        fetch(API_URL + '/api/checkout/draft-order', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(draftPayload)
        })
        .then(function(res) {
          return res.json().then(function(data) {
            if (!res.ok) throw new Error(data.message || 'Sipariş oluşturulamadı.');
            return data;
          });
        })
        .then(function(data) {
          if (!data.checkoutUrl) throw new Error('Ödeme sayfası alınamadı.');
          log('cart:draft-order:response', { checkoutUrl: data.checkoutUrl.substring(0, 60) + '…' });
          // Store the draft order checkout URL — the checkout interception listener will use it
          try { sessionStorage.setItem('perdeCheckoutUrl', data.checkoutUrl); } catch(e) {}

          var cartItemsEl   = document.querySelector('cart-items-component[data-section-id]');
          var cartSectionId = cartItemsEl ? cartItemsEl.dataset.sectionId : '';

          var cartPayload = {
            id:       VARIANT_ID,
            quantity: 1,
            sections: cartSectionId,
            properties: {
              'En':                cfg.en + ' cm',
              'Boy':               cfg.boy + ' cm',
              'Pile Stili':        cfg.pile_stili + ' (x' + cfg.pile_orani + ')',
              'Kanat':             cfg.kanat,
              'Hesaplanan Fiyat':  formatTL(calculatedPrice),
              '_hesaplanan_cents': calculatedCents
            }
          };
          log('cart:add:request', { variantId: cartPayload.id, properties: cartPayload.properties });

          // Step 2: add to cart so the item appears in the cart drawer
          return fetch('/cart/add.js', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(cartPayload)
          });
        })
        .then(function(res) {
          return res.json().then(function(data) {
            if (!res.ok) throw new Error(data.description || 'Sepete eklenemedi.');
            return data;
          });
        })
        .then(function(cartData) {
          var sectionsData = cartData.sections || {};
          log('cart:add:response', { itemCount: cartData.item_count, sectionsRendered: Object.keys(sectionsData).length });
          addToCartBtn.textContent = 'Sepete Eklendi ✓';
          log('cart:add:complete', { price: formatTL(calculatedPrice) });

          var evt = new CustomEvent('cart:update', { bubbles: true, detail: { data: { sections: sectionsData } } });
          document.dispatchEvent(evt);

          var cartDrawer = document.querySelector('cart-drawer-component');
          if (cartDrawer) {
            cartDrawer.open();
            log('cart:drawer:opened');
          } else {
            log('cart:drawer:not-found');
          }
        })
        .catch(function(err) {
          log('cart:error', { message: err.message });
          cartError.textContent = err.message || 'Hata oluştu. Lütfen tekrar deneyin.';
          cartError.classList.add('is-visible');
          addToCartBtn.disabled = false;
          addToCartBtn.textContent = 'Sepete Ekle';
        });
      });

      // Intercept checkout button clicks and redirect to the draft order URL (correct price)
      document.addEventListener('click', function(e) {
        var checkoutUrl;
        try { checkoutUrl = sessionStorage.getItem('perdeCheckoutUrl'); } catch(e2) {}
        if (!checkoutUrl) return;

        var target = e.target.closest('a[href*="/checkout"], button[name="checkout"], [data-checkout-btn]');
        if (target) {
          e.preventDefault();
          e.stopImmediatePropagation();
          log('checkout:intercepted', { url: checkoutUrl.substring(0, 60) + '…' });
          try { sessionStorage.removeItem('perdeCheckoutUrl'); } catch(e2) {}
          window.location.href = checkoutUrl;
        }
      }, true);

    })();

    // Move configurator into the product details column, below the description
    document.addEventListener('DOMContentLoaded', function() {
      var conf = document.getElementById('curtain-configurator');
      var target = document.querySelector('.product-details .group-block-content');
      if (conf && target) {
        conf.classList.remove('page-width');
        target.appendChild(conf);
      }

      // Resolve measurement section anchor dynamically
      var measureLink = document.getElementById('perde-measure-link');
      if (measureLink) {
        var measureSection = document.querySelector('[id*="measurement_videos_pdp"]');
        if (measureSection) {
          measureLink.href = '#' + measureSection.id;
        }
      }
    });
  </script>
{% endif %}

{% schema %}
{
  "name": "Perde Tasarla",
  "tag": "section",
  "settings": [
    {
      "type": "text",
      "id": "draft_order_api_url",
      "label": "Draft Order API URL",
      "info": "PMS sunucu adresi. Örn: https://pms.inanctekstil.store"
    }
  ]
}
{% endschema %}

