  <script>
    (function() {
      // ─── Logger ─────────────────────────────────────────────────────────────
      function log(event, data) {
        if (data !== undefined) {
          console.log('[PerdeTasarla] ' + event, data);
        } else {
          console.log('[PerdeTasarla] ' + event);
        }
      }

      var MIN_EN  = 50;
      var confEl  = document.getElementById('curtain-configurator');
      var MAX_BOY = parseInt(confEl.dataset.maxBoy, 10) || 300;
      window.perdeConfig = window.perdeConfig || {};

      var BASE_PRICE = parseFloat(confEl.dataset.basePrice) || 0;
      var VARIANT_ID = parseInt(confEl.dataset.variantId, 10);
      var API_URL    = confEl.dataset.apiUrl || '';

      log('init', {
        basePrice:  BASE_PRICE,
        variantId:  VARIANT_ID,
        maxBoy:     MAX_BOY,
        apiUrl:     API_URL ? 'configured' : 'MISSING',
        apiUrlHost: API_URL ? API_URL.replace(/^https?:\/\//, '').split('/')[0] : null
      });

      /* ---------- Step 1 ---------- */
      var enInput      = document.getElementById('perde-en');
      var boyInput     = document.getElementById('perde-boy');
      var enError      = document.getElementById('perde-en-error');
      var boyError     = document.getElementById('perde-boy-error');
      var step1Btn     = document.getElementById('perde-step1-btn');
      var step1El      = document.getElementById('perde-step-1');
      var summary1     = document.getElementById('perde-summary-1');
      var summary1Text = document.getElementById('perde-summary-1-text');
      var step2El      = document.getElementById('perde-step-2');

      function validateEn() {
        var v = parseInt(enInput.value, 10);
        var ok = !isNaN(v) && v >= MIN_EN;
        enInput.classList.toggle('is-invalid', !ok && enInput.value !== '');
        enError.classList.toggle('is-visible', !ok && enInput.value !== '');
        if (!ok && enInput.value !== '') log('validate:en:fail', { value: enInput.value, min: MIN_EN });
        return ok;
      }

      function validateBoy() {
        var v = parseInt(boyInput.value, 10);
        var ok = !isNaN(v) && v >= 1 && v <= MAX_BOY;
        boyInput.classList.toggle('is-invalid', !ok && boyInput.value !== '');
        boyError.classList.toggle('is-visible', !ok && boyInput.value !== '');
        if (!ok && boyInput.value !== '') log('validate:boy:fail', { value: boyInput.value, max: MAX_BOY });
        return ok;
      }

      function updateStep1Btn() {
        step1Btn.disabled = !(validateEn() && validateBoy());
      }

      enInput.addEventListener('input', updateStep1Btn);
      boyInput.addEventListener('input', updateStep1Btn);

      step1Btn.addEventListener('click', function() {
        if (step1Btn.disabled) return;
        window.perdeConfig.en  = parseInt(enInput.value, 10);
        window.perdeConfig.boy = parseInt(boyInput.value, 10);
        log('step1:complete', { en: window.perdeConfig.en, boy: window.perdeConfig.boy });
        step1El.classList.remove('is-active');
        summary1Text.textContent = window.perdeConfig.en + ' x ' + window.perdeConfig.boy + ' cm';
        summary1.classList.add('is-visible');
        step2El.classList.add('is-active');
      });

      /* ---------- Step 2 ---------- */
      var step2Btn     = document.getElementById('perde-step2-btn');
      var summary2     = document.getElementById('perde-summary-2');
      var summary2Text = document.getElementById('perde-summary-2-text');
      var pileCards    = document.querySelectorAll('.perde-conf__pile-card');
      var step3El      = document.getElementById('perde-step-3');
      var summary3     = document.getElementById('perde-summary-3');

      pileCards.forEach(function(card) {
        card.addEventListener('click', function() {
          pileCards.forEach(function(c) {
            c.classList.remove('is-selected');
            c.setAttribute('aria-pressed', 'false');
          });
          card.classList.add('is-selected');
          card.setAttribute('aria-pressed', 'true');
          window.perdeConfig.pile_stili = card.dataset.pile;
          window.perdeConfig.pile_orani = parseFloat(card.dataset.ratio);
          step2Btn.disabled = false;
          log('step2:select', { pile: card.dataset.pile, ratio: card.dataset.ratio });
        });
        card.addEventListener('keydown', function(e) {
          if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); card.click(); }
        });
      });

      step2Btn.addEventListener('click', function() {
        if (step2Btn.disabled) return;
        log('step2:complete', { pile: window.perdeConfig.pile_stili, ratio: window.perdeConfig.pile_orani });
        step2El.classList.remove('is-active');
        summary2Text.textContent = window.perdeConfig.pile_stili;
        summary2.classList.add('is-visible');
        step3El.classList.add('is-active');
      });

      /* ---------- Step 3 ---------- */
      var step3Btn     = document.getElementById('perde-step3-btn');
      var summary3Text = document.getElementById('perde-summary-3-text');
      var kanatOptions = document.querySelectorAll('.perde-conf__kanat-option');

      kanatOptions.forEach(function(opt) {
        opt.addEventListener('click', function() {
          kanatOptions.forEach(function(o) {
            o.classList.remove('is-selected');
            o.setAttribute('aria-pressed', 'false');
          });
          opt.classList.add('is-selected');
          opt.setAttribute('aria-pressed', 'true');
          window.perdeConfig.kanat       = opt.dataset.kanat;
          window.perdeConfig.kanat_count = parseInt(opt.dataset.count, 10);
          step3Btn.disabled = false;
          log('step3:select', { kanat: opt.dataset.kanat, count: opt.dataset.count });
        });
        opt.addEventListener('keydown', function(e) {
          if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); opt.click(); }
        });
      });

      step3Btn.addEventListener('click', function() {
        if (step3Btn.disabled) return;
        log('step3:complete', { kanat: window.perdeConfig.kanat, count: window.perdeConfig.kanat_count });
        step3El.classList.remove('is-active');
        summary3Text.textContent = window.perdeConfig.kanat;
        summary3.classList.add('is-visible');
        showStep4();
      });

      /* ---------- Step 4 ---------- */
      var step4El         = document.getElementById('perde-step-4');
      var priceDisplay    = document.getElementById('perde-price-display');
      var reviewEn        = document.getElementById('perde-review-en');
      var reviewBoy       = document.getElementById('perde-review-boy');
      var reviewPile      = document.getElementById('perde-review-pile');
      var reviewKanat     = document.getElementById('perde-review-kanat');
      var disclaimerCheck = document.getElementById('perde-disclaimer-check');
      var cartError       = document.getElementById('perde-cart-error');
      var addToCartBtn    = document.getElementById('perde-add-to-cart-btn');

      function formatTL(amount) {
        return amount.toLocaleString('tr-TR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + ' TL';
      }

      function calcPrice() {
        var en    = window.perdeConfig.en || 0;
        var ratio = window.perdeConfig.pile_orani || 1;
        var count = window.perdeConfig.kanat_count || 1;
        var price = (en / 100) * ratio * count * BASE_PRICE;
        log('price:formula', {
          formula: '(' + en + '/100) × ' + ratio + ' × ' + count + ' × ' + BASE_PRICE,
          result: price,
          resultFormatted: formatTL(price)
        });
        return price;
      }

      function showStep4() {
        var price = calcPrice();
        reviewEn.textContent     = (window.perdeConfig.en || '—') + ' cm';
        reviewBoy.textContent    = (window.perdeConfig.boy || '—') + ' cm';
        reviewPile.textContent   = window.perdeConfig.pile_stili || '—';
        reviewKanat.textContent  = window.perdeConfig.kanat || '—';
        priceDisplay.textContent = formatTL(price);
        step4El.classList.add('is-active');
        log('step4:show', {
          config: {
            en: window.perdeConfig.en, boy: window.perdeConfig.boy,
            pile: window.perdeConfig.pile_stili, ratio: window.perdeConfig.pile_orani,
            kanat: window.perdeConfig.kanat, count: window.perdeConfig.kanat_count
          },
          price: formatTL(price)
        });
      }

      disclaimerCheck.addEventListener('change', function() {
        addToCartBtn.disabled = !disclaimerCheck.checked;
        log('disclaimer:' + (disclaimerCheck.checked ? 'accepted' : 'unaccepted'));
      });

      // Clear any stale draft order URL when configurator loads
      try { sessionStorage.removeItem('perdeCheckoutUrl'); } catch(e) {}

      addToCartBtn.addEventListener('click', function() {
        if (addToCartBtn.disabled) return;
        if (!API_URL) {
          cartError.textContent = 'Sipariş API adresi yapılandırılmamış. Lütfen yöneticiyle iletişime geçin.';
          cartError.classList.add('is-visible');
          log('error:no-api-url');
          return;
        }

        addToCartBtn.disabled = true;
        addToCartBtn.textContent = 'Hazırlanıyor…';
        cartError.classList.remove('is-visible');
        cartError.textContent = '';

        var cfg = window.perdeConfig;
        var calculatedPrice = calcPrice();
        var calculatedCents = Math.round(calculatedPrice * 100);

        var draftPayload = {
          variantId:  VARIANT_ID,
          en:         cfg.en,
          boy:        cfg.boy,
          pileStili:  cfg.pile_stili,
          pileOrani:  cfg.pile_orani,
          kanat:      cfg.kanat,
          kanatCount: cfg.kanat_count
        };
        log('cart:draft-order:request', draftPayload);

        // Step 1: create draft order to get a checkout URL with the correct calculated price
        fetch(API_URL + '/api/checkout/draft-order', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(draftPayload)
        })
        .then(function(res) {
          return res.json().then(function(data) {
            if (!res.ok) throw new Error(data.message || 'Sipariş oluşturulamadı.');
            return data;
          });
        })
        .then(function(data) {
          if (!data.checkoutUrl) throw new Error('Ödeme sayfası alınamadı.');
          log('cart:draft-order:response', { checkoutUrl: data.checkoutUrl.substring(0, 60) + '…' });
          // Store the draft order checkout URL — the checkout interception listener will use it
          try { sessionStorage.setItem('perdeCheckoutUrl', data.checkoutUrl); } catch(e) {}

          var cartItemsEl   = document.querySelector('cart-items-component[data-section-id]');
          var cartSectionId = cartItemsEl ? cartItemsEl.dataset.sectionId : '';

          var cartPayload = {
            id:       VARIANT_ID,
            quantity: 1,
            sections: cartSectionId,
            properties: {
              'En':                cfg.en + ' cm',
              'Boy':               cfg.boy + ' cm',
              'Pile Stili':        cfg.pile_stili + ' (x' + cfg.pile_orani + ')',
              'Kanat':             cfg.kanat,
              'Hesaplanan Fiyat':  formatTL(calculatedPrice),
              '_hesaplanan_cents': calculatedCents
            }
          };
          log('cart:add:request', { variantId: cartPayload.id, properties: cartPayload.properties });

          // Step 2: add to cart so the item appears in the cart drawer
          return fetch('/cart/add.js', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(cartPayload)
          });
        })
        .then(function(res) {
          return res.json().then(function(data) {
            if (!res.ok) throw new Error(data.description || 'Sepete eklenemedi.');
            return data;
          });
        })
        .then(function(cartData) {
          var sectionsData = cartData.sections || {};
          log('cart:add:response', { itemCount: cartData.item_count, sectionsRendered: Object.keys(sectionsData).length });
          addToCartBtn.textContent = 'Sepete Eklendi ✓';
          log('cart:add:complete', { price: formatTL(calculatedPrice) });

          var evt = new CustomEvent('cart:update', { bubbles: true, detail: { data: { sections: sectionsData } } });
          document.dispatchEvent(evt);

          var cartDrawer = document.querySelector('cart-drawer-component');
          if (cartDrawer) {
            cartDrawer.open();
            log('cart:drawer:opened');
          } else {
            log('cart:drawer:not-found');
          }
        })
        .catch(function(err) {
          log('cart:error', { message: err.message });
          cartError.textContent = err.message || 'Hata oluştu. Lütfen tekrar deneyin.';
          cartError.classList.add('is-visible');
          addToCartBtn.disabled = false;
          addToCartBtn.textContent = 'Sepete Ekle';
        });
      });

      // Intercept checkout button clicks and redirect to the draft order URL (correct price)
      document.addEventListener('click', function(e) {
        var checkoutUrl;
        try { checkoutUrl = sessionStorage.getItem('perdeCheckoutUrl'); } catch(e2) {}
        if (!checkoutUrl) return;

        var target = e.target.closest('a[href*="/checkout"], button[name="checkout"], [data-checkout-btn]');
        if (target) {
          e.preventDefault();
          e.stopImmediatePropagation();
          log('checkout:intercepted', { url: checkoutUrl.substring(0, 60) + '…' });
          try { sessionStorage.removeItem('perdeCheckoutUrl'); } catch(e2) {}
          window.location.href = checkoutUrl;
        }
      }, true);

    })();

    // Move configurator into the product details column, below the description
    document.addEventListener('DOMContentLoaded', function() {
      var conf = document.getElementById('curtain-configurator');
      var target = document.querySelector('.product-details .group-block-content');
      if (conf && target) {
        conf.classList.remove('page-width');
        target.appendChild(conf);
      }

      // Resolve measurement section anchor dynamically
      var measureLink = document.getElementById('perde-measure-link');
      if (measureLink) {
        var measureSection = document.querySelector('[id*="measurement_videos_pdp"]');
        if (measureSection) {
          measureLink.href = '#' + measureSection.id;
        }
      }
    });
  </script>
{% endif %}

